import React, { useState, useEffect } from 'react';
import { authAPI, mongoAPI } from '../services/api';
import { splitQuestions } from '../utils/splitQuestions';
import { Button, Select, Textarea, Alert, PageHeader, Card, Badge, EmptyState } from '../components/ui';
import ResultsPanel from '../components/ui/ResultsPanel';
import { Leaf, Send, Sparkles, CheckSquare, Square } from 'lucide-react';
import './QueryPage.css';
import './MongoPage.css';

const SAMPLE_QUESTIONS = [
  'Show top 10 customers by total spent',
  'Find all orders from the Asia Pacific region',
  'Show monthly revenue trend',
  'Which customers have the most orders and what is their average order value?',
  'Find customers who have not ordered in 90 days',
];

export default function MongoPage() {
  const [connections, setConnections]     = useState([]);
  const [selectedConn, setSelectedConn]   = useState('');
  const [databases, setDatabases]         = useState([]);
  const [collections, setCollections]     = useState([]);
  const [selectedColls, setSelectedColls] = useState([]); // multi-select
  const [dbName, setDbName]               = useState('');
  const [question, setQuestion]           = useState('');
  const [results, setResults]             = useState([]);
  const [loading, setLoading]             = useState(false);
  const [error, setError]                 = useState('');
  const [loadingDbs, setLoadingDbs]       = useState(false);
  const [loadingColls, setLoadingColls]   = useState(false);
  const [mongoUri, setMongoUri]           = useState('');

  useEffect(() => {
    authAPI.connections()
      .then(r => {
        const mg = (r.data || []).filter(c => c.db_type === 'mongodb');
        setConnections(mg);
        if (mg.length) setSelectedConn(String(mg[0].id));
      }).catch(() => setConnections([]));
  }, []);

  const conn = connections.find(c => String(c.id) === String(selectedConn));

  // Fetch URI + databases when connection changes
  useEffect(() => {
    if (!conn) return;
    setDatabases([]); setDbName(''); setCollections([]); setSelectedColls([]);
    setMongoUri(''); setLoadingDbs(true);
    authAPI.getUri(conn.id)
      .then(r => {
        const uri = r.data?.uri || r.data?.connection_string || '';
        if (!uri) { setError('Could not retrieve MongoDB URI.'); setLoadingDbs(false); return; }
        setMongoUri(uri);
        return mongoAPI.listDbs(uri);
      })
      .then(r => {
        const dbs = r?.data?.databases || [];
        setDatabases(dbs);
        if (dbs.length === 1) setDbName(dbs[0]);
      })
      .catch(e => setError('Failed to load databases: ' + (e.response?.data?.detail || e.message)))
      .finally(() => setLoadingDbs(false));
  }, [selectedConn]);

  // Fetch ALL collections when DB changes, auto-select all
  useEffect(() => {
    if (!mongoUri || !dbName) return;
    setCollections([]); setSelectedColls([]); setLoadingColls(true);
    mongoAPI.listColls(mongoUri, dbName)
      .then(r => {
        const colls = r?.data?.collections || [];
        setCollections(colls);
        setSelectedColls(colls); // select all by default
      })
      .catch(e => setError('Failed to load collections: ' + (e.response?.data?.detail || e.message)))
      .finally(() => setLoadingColls(false));
  }, [dbName, mongoUri]);

  const toggleColl = coll => setSelectedColls(prev =>
    prev.includes(coll) ? prev.filter(c => c !== coll) : [...prev, coll]
  );
  const toggleAll = () => setSelectedColls(
    selectedColls.length === collections.length ? [] : [...collections]
  );

  const runQuery = async () => {
    if (!question.trim())       return setError('Please enter a question.');
    if (!conn)                  return setError('Please select a connection.');
    if (!dbName)                return setError('Please select a database.');
    if (!selectedColls.length)  return setError('Please select at least one collection.');
    setLoading(true); setError(''); setResults([]);
    try {
      const questions = splitQuestions(question);
      const responses = await Promise.all(
        questions.map(({ display, query }) => {
          // Use join endpoint for multiple collections, single endpoint for one
          const apiCall = selectedColls.length > 1
            ? mongoAPI.nlQueryJoin({ mongo_uri: mongoUri, db_name: dbName, collections: selectedColls, question: query, limit: 100 })
            : mongoAPI.nlQuery({ mongo_uri: mongoUri, db_name: dbName, collection: selectedColls[0], question: query, limit: 100 });
          return apiCall
            .then(r => ({ ok: true, question: display, data: r.data }))
            .catch(e => ({ ok: false, question: display, error: e.response?.data?.detail || e.message || 'Failed' }));
        })
      );
      setResults(responses);
    } catch (err) {
      setError(err.response?.data?.detail || err.message || 'Query failed.');
    } finally { setLoading(false); }
  };

  return (
    <div className="query-page fade-in">
      <PageHeader
        title="MongoDB Query"
        subtitle="Query one or multiple collections with natural language"
        actions={<Badge color="green"><Leaf size={12}/> MongoDB</Badge>}
      />

      <div className="query-layout">
        <div className="query-input-col">
          <Card>
            <div className="query-form">
              {connections.length === 0 ? (
                <EmptyState icon={<Leaf size={22}/>} title="No MongoDB connections"
                  description="Add a MongoDB connection in the Connections page first." />
              ) : (
                <>
                  <Select label="Connection" value={selectedConn}
                    onChange={e => { setSelectedConn(e.target.value); setError(''); }}>
                    {connections.map(c => (
                      <option key={c.id} value={String(c.id)}>{c.name || `Connection ${c.id}`}</option>
                    ))}
                  </Select>

                  <Select label="Database" value={dbName} onChange={e => setDbName(e.target.value)}
                    disabled={loadingDbs || !databases.length}>
                    <option value="">
                      {loadingDbs ? 'Loading...' : databases.length ? 'Select database' : 'No databases found'}
                    </option>
                    {databases.map(d => <option key={d} value={d}>{d}</option>)}
                  </Select>

                  {/* Collections multi-select */}
                  {dbName && (
                    <div className="coll-select-group">
                      <div className="coll-select-label">
                        <span>Collections</span>
                        {collections.length > 0 && (
                          <button className="coll-toggle-all" onClick={toggleAll}>
                            {selectedColls.length === collections.length ? 'Deselect all' : 'Select all'}
                          </button>
                        )}
                      </div>
                      {loadingColls ? (
                        <div className="coll-loading">Loading collections...</div>
                      ) : collections.length === 0 ? (
                        <div className="coll-loading">No collections found</div>
                      ) : (
                        <div className="coll-list">
                          {collections.map(c => (
                            <label key={c} className={`coll-item ${selectedColls.includes(c) ? 'selected' : ''}`}>
                              <input type="checkbox" checked={selectedColls.includes(c)} onChange={() => toggleColl(c)} />
                              {selectedColls.includes(c) ? <CheckSquare size={14}/> : <Square size={14}/>}
                              <span>{c}</span>
                            </label>
                          ))}
                        </div>
                      )}
                      {selectedColls.length > 1 && (
                        <div className="coll-join-hint">
                          <Leaf size={11}/> {selectedColls.length} collections selected — will use $lookup joins automatically
                        </div>
                      )}
                    </div>
                  )}

                  <Textarea label="Your Question" value={question} onChange={e => setQuestion(e.target.value)}
                    placeholder="e.g. Show top 10 customers by total spent and also monthly revenue trend"
                    rows={4}
                    onKeyDown={e => { if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) runQuery(); }}
                    hint="Tip: ask multiple questions at once! Ctrl+Enter to run" />

                  {error && <Alert type="error" onClose={() => setError('')}>{error}</Alert>}

                  <Button onClick={runQuery} loading={loading} size="lg"
                    icon={loading ? null : <Send size={15}/>} style={{ width: '100%' }}>
                    {loading ? 'Running query...' : 'Run Query'}
                  </Button>
                </>
              )}
            </div>
          </Card>

          <div className="sample-questions">
            <div className="sample-title"><Sparkles size={13}/> Sample questions</div>
            {SAMPLE_QUESTIONS.map(q => (
              <button key={q} className="sample-btn" onClick={() => setQuestion(q)}>{q}</button>
            ))}
          </div>
        </div>

        <div className="query-result-col">
          {loading && (
            <Card className="query-loading-card">
              <div className="query-loading">
                <div className="query-loading-spinner" />
                <div>
                  <div className="query-loading-title">Running AI pipeline...</div>
                  <div className="query-loading-sub">
                    {selectedColls.length > 1
                      ? `Joining ${selectedColls.length} collections → Gemini → Pipeline → EDA`
                      : 'Schema → Gemini → Query → EDA'}
                  </div>
                </div>
              </div>
            </Card>
          )}
          {!loading && results.length > 0 && (
            <div className="multi-results">
              {results.map((r, i) => (
                <div key={i} className="multi-result-block">
                  {results.length > 1 && (
                    <div className="multi-result-label">
                      <span className="multi-result-num">{i + 1}</span>
                      <span className="multi-result-q">{r.question}</span>
                    </div>
                  )}
                  {r.ok
                    ? <ResultsPanel key={r.question} result={r.data} />
                    : <Alert type="error">{typeof r.error === 'string' ? r.error : JSON.stringify(r.error)}</Alert>}
                </div>
              ))}
            </div>
          )}
          {!loading && results.length === 0 && (
            <div className="query-empty">
              <div className="query-empty-icon"><Leaf size={32}/></div>
              <div className="query-empty-title">Ready to query</div>
              <div className="query-empty-sub">Select collections and ask your question — pick multiple for cross-collection queries</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
